    90→    };
    91→
    92→    const removeFile = (index: number) => {
    93→        setFiles(prev => prev.filter((_, i) => i !== index));
    94→    };
    95→
    96→    const addLink = () => {
    97→        if (!linkInput.trim()) return;
    98→        setLinks(prev => [...prev, linkInput]);
    99→        toast.success("Lien ajouté");
   100→        setLinkInput("");
   101→        setIsLinkOpen(false);
   102→    };
   103→
   104→    const removeLink = (index: number) => {
   105→        setLinks(prev => prev.filter((_, i) => i !== index));
   106→    };
   107→
   108→    // Focus on mount
   109→    useEffect(() => {
   110→        if (viewMode === "INPUT") {
   111→            textareaRef.current?.focus();
   112→        }
   113→    }, [viewMode]);
   114→
   115→    const hasContent = input.trim().length > 0 || files.length > 0 || links.length > 0;
   116→
   117→    return (
   118→        <div className="min-h-screen bg-background text-foreground flex flex-col font-sans selection:bg-[#F75105]/30">
   119→            <SiteHeader variant="app" />
   120→            <AuthModal />
   121→
   122→            {/* Main Content using Flex to Center */}
   123→            <main className="flex-1 w-full max-w-5xl mx-auto px-6 flex flex-col items-center justify-center gap-12 pb-24">
   124→
   125→                {/* Hero Text (Only in Input Mode) */}
   126→                {viewMode === "INPUT" && (
   127→                    <div className="animate-in fade-in slide-in-from-bottom-4 duration-500 flex flex-col gap-6 text-center max-w-2xl">
   128→                        <h1 className="text-6xl md:text-7xl font-light text-white tracking-tight leading-[1.0] font-sans">
   129→                            {t?.capture?.hero || "Capture Your Vision"}
   130→                        </h1>
   131→                        <p className="text-[#D2D3D4] font-light text-lg md:text-xl tracking-wide max-w-lg mx-auto leading-relaxed">
   132→                            {t?.capture?.helper || "From raw thought to structured project in seconds."}
   133→                        </p>
   134→                    </div>
   135→                )}
   136→
   137→                {/* INPUT CARD - MODERN ROUNDED (Radius 24px) */}
   138→                {viewMode === "INPUT" && (
   139→                    <div className="w-full max-w-3xl bg-[--bg-card] rounded-[24px] border border-[--border-default] p-8 shadow-2xl relative overflow-visible transition-all duration-300 hover:border-[--border-strong] animate-in zoom-in-95 backdrop-blur-sm group/card">
   140→
   141→                        {/* Textarea */}
   142→                        <textarea
   143→                            ref={textareaRef}
   144→                            value={input}
   145→                            onChange={(e) => setInput(e.target.value)}
   146→                            onKeyDown={handleKeyDown}
   147→                            className="w-full h-40 bg-transparent resize-none outline-none text-xl text-white placeholder:text-[#5D5C5B] font-light leading-relaxed scrollbar-hide"
   148→                            placeholder={t?.capture?.placeholder || "Describe your idea..."}
   149→                            autoFocus
   150→                        />
   151→
   152→                        {/* Attachments Preview */}
   153→                        {(files.length > 0 || links.length > 0) && (
   154→                            <div className="flex flex-wrap gap-2 mt-4 mb-4 pt-4 border-t border-[--border-subtle]">
   155→                                {files.map((file, index) => (
   156→                                    <div
   157→                                        key={index}
   158→                                        className="flex items-center gap-2 text-xs bg-[--bg-secondary] border border-[--border-default] rounded-full px-4 py-2 text-[#D2D3D4] animate-in fade-in"
   159→                                    >
   160→                                        <Paperclip className="w-3 h-3 text-[#5D5C5B]" />
   161→                                        <span className="max-w-[150px] truncate">{file.name}</span>
   162→                                        <button
   163→                                            onClick={() => removeFile(index)}
   164→                                            className="ml-2 text-[#5D5C5B] hover:text-[#F75105] transition-colors"
   165→                                        >
   166→                                            <X className="w-3 h-3" />
   167→                                        </button>
   168→                                    </div>
   169→                                ))}
   170→                                {links.map((link, index) => (
   171→                                    <div
   172→                                        key={index}
   173→                                        className="flex items-center gap-2 text-xs bg-[--bg-secondary] border border-[--border-default] rounded-full px-4 py-2 text-[#D2D3D4] animate-in fade-in"
   174→                                    >
   175→                                        <LinkIcon className="w-3 h-3 text-[#F75105]" />
   176→                                        <span className="max-w-[150px] truncate">{link}</span>
   177→                                        <button
   178→                                            onClick={() => removeLink(index)}
   179→                                            className="ml-2 text-[#5D5C5B] hover:text-[#F75105] transition-colors"
   180→                                        >
   181→                                            <X className="w-3 h-3" />
   182→                                        </button>
   183→                                    </div>
   184→                                ))}
   185→                            </div>
   186→                        )}
   187→
   188→                        {/* Hidden File Input */}
   189→                        <input
   190→                            type="file"
   191→                            ref={fileInputRef}
   192→                            className="hidden"
   193→                            onChange={handleFileChange}
   194→                        />
   195→
   196→                        {/* Actions Toolbar */}
   197→                        <div className="flex justify-between items-end mt-4">
   198→                            {/* Tools (Bottom Left) */}
   199→                            <div className="flex gap-2">
   200→                                {/* Attach File */}
   201→                                <button
   202→                                    onClick={handleAttachFile}
   203→                                    className="p-3 rounded-full hover:bg-[--bg-secondary] text-[#5D5C5B] hover:text-white transition-all duration-300 active:scale-95 group/icon"
   204→                                    title={t?.capture?.attachFile || "Attach File"}
   205→                                >
   206→                                    <Paperclip className="w-5 h-5 transition-colors" />
   207→                                </button>
   208→
   209→                                {/* Add Link */}
   210→                                <Popover open={isLinkOpen} onOpenChange={setIsLinkOpen}>
   211→                                    <PopoverTrigger asChild>
   212→                                        <button
   213→                                            className={cn(
   214→                                                "p-3 rounded-full transition-all duration-300 active:scale-95 group/icon",
   215→                                                isLinkOpen ? "bg-[--bg-secondary] text-white" : "hover:bg-[--bg-secondary] text-[#5D5C5B] hover:text-white"
   216→                                            )}
   217→                                            title={t?.capture?.addLink || "Add Link"}
   218→                                        >
   219→                                            <LinkIcon className="w-5 h-5 transition-colors" />
   220→                                        </button>
   221→                                    </PopoverTrigger>
   222→                                    <PopoverContent className="w-96 p-4 bg-[--bg-card] border border-[--border-default] rounded-[20px] shadow-2xl" align="start" sideOffset={12}>
   223→                                        <div className="flex gap-3">
   224→                                            <input
   225→                                                className="flex-1 px-4 py-3 text-sm bg-[--bg-secondary] border border-[--border-subtle] rounded-lg text-white placeholder:text-[#5D5C5B] focus:outline-none focus:border-[#F75105] transition-all font-light"
   226→                                                placeholder="https://example.com"
   227→                                                value={linkInput}
   228→                                                onChange={(e) => setLinkInput(e.target.value)}
   229→                                                onKeyDown={(e) => e.key === "Enter" && addLink()}
   230→                                                autoFocus
   231→                                            />
   232→                                            <button
   233→                                                onClick={addLink}
   234→                                                className="px-6 py-2 text-sm font-medium bg-[#F75105] text-white rounded-lg hover:bg-[#F78E21] hover:shadow-[0_0_20px_rgba(247,81,5,0.4)] transition-all"
   235→                                            >
   236→                                                Add
   237→                                            </button>
   238→                                        </div>
   239→                                    </PopoverContent>
   240→                                </Popover>
   241→
   242→                                {/* Voice Input (Static Orange Active State - Color Only) */}
   243→                                <button
   244→                                    onClick={toggleRecording}
   245→                                    className={cn(
   246→                                        "p-3 rounded-full transition-all duration-300 active:scale-95 group/mic",
   247→                                        isRecording
   248→                                            ? "text-[#F75105] hover:bg-[--bg-secondary]"
   249→                                            : "hover:bg-[--bg-secondary] text-[#5D5C5B] hover:text-white"
   250→                                    )}
   251→                                    title={t?.capture?.voiceInput || "Voice Input"}
   252→                                >
   253→                                    <Mic className="w-5 h-5" />
   254→                                </button>
   255→                            </div>
   256→
   257→                            {/* Submit Button (Logo Animation Style: ArrowDownLeft -> Rotate 180) */}
   258→                            <button
   259→                                onClick={handleSubmit}
   260→                                disabled={!hasContent}
   261→                                className={cn(
   262→                                    "relative w-14 h-14 flex items-center justify-center rounded-full transition-all duration-500 shadow-lg group/submit",
   263→                                    hasContent
   264→                                        ? "bg-[#F75105] hover:bg-[#F78E21] hover:scale-110 shadow-[0_0_20px_rgba(247,81,5,0.3)] hover:shadow-[0_0_35px_rgba(247,81,5,0.6)] cursor-pointer"
   265→                                        : "bg-[#2F323A] cursor-not-allowed opacity-50"
   266→                                )}
   267→                                title={t?.capture?.submit || "Analyze"}
   268→                            >
   269→                                {hasContent ? (
   270→                                    <ArrowDownLeft className="w-6 h-6 text-white transition-transform duration-500 group-hover/submit:rotate-180" strokeWidth={3} />
