     1→"use client";
     2→
     3→import { useEffect, useState, useMemo } from "react";
     4→import { useLanguageStore } from "@/store/language-store";
     5→import { useRouter } from "next/navigation";
     6→import { SiteHeader } from "@/components/layout/site-header";
     7→import { ProCard } from "@/components/workspace/pro-card";
     8→import { FloatingDock } from "@/components/workspace/floating-dock";
     9→import { DossierSettingsDialog } from "@/components/workspace/dossier-settings-dialog";
    10→import { cn } from "@/lib/utils";
    11→
    12→interface Project {
    13→    id: string;
    14→    title?: string;
    15→    text: string;
    16→    description?: string;
    17→    color?: string;
    18→    globalScore?: number;
    19→    recommendation?: string;
    20→    confidenceLevel?: string;
    21→    viabilityScore?: number;
    22→    classification?: string;
    23→    timestamp: string;
    24→    isDemo?: boolean;
    25→    analysis?: any;
    26→}
    27→
    28→function getProjectDecision(p: Project): string {
    29→    return p.recommendation ?? p.classification ?? "DRAFT";
    30→}
    31→
    32→function getProjectTitle(p: Project): string {
    33→    return p.title ?? p.text;
    34→}
    35→
    36→export default function WorkspacePage() {
    37→    const { t } = useLanguageStore();
    38→    const router = useRouter();
    39→
    40→    const [projects, setProjects] = useState<Project[]>([]);
    41→    const [viewMode, setViewMode] = useState<"grid" | "list">("grid");
    42→    const [searchQuery, setSearchQuery] = useState("");
    43→    const [activeFilter, setActiveFilter] = useState<string>("ALL");
    44→    const [sortBy, setSortBy] = useState<string>("date");
    45→
    46→    // Settings dialog state
    47→    const [settingsProject, setSettingsProject] = useState<Project | null>(null);
    48→    const [settingsOpen, setSettingsOpen] = useState(false);
    49→
    50→    // Initial Load Logic
    51→    useEffect(() => {
    52→        const currentIdea = localStorage.getItem("k3rn_active_project");
    53→        const storedProjects = JSON.parse(localStorage.getItem("k3rn_projects") || "[]");
    54→
    55→        if (currentIdea) {
    56→            const idea = JSON.parse(currentIdea);
    57→            const exists = storedProjects.some((p: any) => p.timestamp === idea.timestamp);
    58→            if (!exists) {
    59→                const newProject: Project = {
    60→                    id: idea.id || crypto.randomUUID(),
    61→                    title: idea.title,
    62→                    text: idea.text || "",
    63→                    globalScore: idea.globalScore ?? idea.analysis?.viabilityScore,
    64→                    recommendation: idea.recommendation ?? idea.analysis?.classification,
    65→                    confidenceLevel: idea.confidenceLevel,
    66→                    viabilityScore: idea.viabilityScore ?? idea.analysis?.viabilityScore,
    67→                    classification: idea.classification ?? idea.analysis?.classification,
    68→                    timestamp: idea.timestamp,
    69→                    isDemo: idea.isDemo,
    70→                    analysis: idea.analysis,
    71→                };
    72→                storedProjects.unshift(newProject);
    73→                localStorage.setItem("k3rn_projects", JSON.stringify(storedProjects));
    74→                localStorage.removeItem("k3rn_active_project");
    75→            }
    76→        }
    77→
    78→        if (storedProjects.length === 0) {
    79→            const mocks: Project[] = [
    80→                { id: "1", title: "Drone Fleet SaaS Platform", text: "Plateforme SaaS de gestion de flottes de drones autonomes", globalScore: 92, recommendation: "GO", timestamp: new Date().toISOString(), isDemo: true, description: "A comprehensive solution for autonomous drone logistics, featuring real-time telemetry, AI-driven pathfinding, and predictive maintenance." },
    81→                { id: "2", title: "NFT Patent Marketplace", text: "Marketplace NFT pour brevets industriels", globalScore: 38, recommendation: "KILL", timestamp: new Date(Date.now() - 86400000).toISOString(), isDemo: true, description: "Attempting to tokenize IP rights on the blockchain. Initial market validation suggests low demand." },
    82→                { id: "3", title: "AI Film Script Generator", text: "IA générative pour scripts de films", globalScore: 78, recommendation: "EXPLORE", timestamp: new Date(Date.now() - 172800000).toISOString(), isDemo: true, description: "Leveraging LLMs for creative writing assistance. The prototype shows promise but lacks structure." },
    83→                { id: "4", title: "MeowNet - Social Network for Cats", text: "Réseau social pour chats (MeowNet)", globalScore: 22, recommendation: "PARK", timestamp: new Date(Date.now() - 432000000).toISOString(), isDemo: true, description: "Niche social network. Market size is questionable despite high engagement potential." },
    84→                { id: "5", title: "Quantum Encryption Key", text: "Clé de chiffrement quantique", globalScore: 88, recommendation: "GO", timestamp: new Date(Date.now() - 500000000).toISOString(), isDemo: true, description: "Next-gen security infrastructure for fintech. Critical need in the post-quantum era." },
    85→            ];
    86→            setProjects(mocks);
    87→        } else {
    88→            setProjects(storedProjects);
    89→        }
    90→    }, []);
    91→
    92→    const filteredProjects = useMemo(() => {
    93→        let result = projects.filter((p) => {
    94→            const q = searchQuery.toLowerCase();
    95→            const matchesSearch =
    96→                getProjectTitle(p).toLowerCase().includes(q) ||
    97→                p.text.toLowerCase().includes(q) ||
    98→                getProjectDecision(p).toLowerCase().includes(q);
    99→
   100→            const matchesFilter = activeFilter === "ALL" || getProjectDecision(p) === activeFilter;
   101→
   102→            return matchesSearch && matchesFilter;
   103→        });
   104→
   105→        // Sort
   106→        if (sortBy === "score") {
   107→            result = [...result].sort((a, b) => (b.globalScore ?? 0) - (a.globalScore ?? 0));
   108→        } else {
   109→            result = [...result].sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime());
   110→        }
   111→
   112→        return result;
   113→    }, [projects, searchQuery, activeFilter, sortBy]);
   114→
   115→    // Save settings for a project
   116→    function handleSaveSettings(updates: { title?: string; description?: string; color?: string }) {
   117→        if (!settingsProject) return;
   118→        const updated = projects.map((p) =>
   119→            p.id === settingsProject.id ? { ...p, ...updates } : p
   120→        );
   121→        setProjects(updated);
   122→        // Persist to localStorage (skip if all demo)
   123→        const nonDemo = updated.filter((p) => !p.isDemo);
   124→        if (nonDemo.length > 0 || updated.some((p) => p.isDemo && (updates.title || updates.description || updates.color))) {
   125→            localStorage.setItem("k3rn_projects", JSON.stringify(updated));
   126→        }
   127→    }
   128→
   129→    return (
   130→        <div className="min-h-screen bg-background text-foreground font-sans selection:bg-[--color-brand-primary]/30 flex flex-col overflow-x-hidden">
   131→            <SiteHeader variant="app" />
   132→
   133→            <div className="relative z-10 flex-1 pt-24 pb-40 px-6 md:px-12 w-full max-w-[1600px] mx-auto">
   134→
   135→                {/* Header */}
   136→                <div className="flex justify-between items-end mb-12">
   137→                    <div>
   138→                        <h1 className="text-3xl font-medium tracking-tight text-[--color-text-primary] mb-2">
   139→                            Dossiers
   140→                        </h1>
   141→                        <p className="text-[--color-text-muted] text-sm font-medium">
   142→                            {filteredProjects.length} projet{filteredProjects.length !== 1 ? "s" : ""} actif{filteredProjects.length !== 1 ? "s" : ""}
   143→                        </p>
   144→                    </div>
   145→                </div>
   146→
   147→                {/* Grid / List */}
   148→                <div className={cn(
   149→                    "grid gap-6 animate-in fade-in zoom-in-95 duration-500",
   150→                    viewMode === "grid"
   151→                        ? "grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4"
   152→                        : "grid-cols-1"
